'use strict';

/**
 * scripts/seed-knowledge-hvac.js
 *
 * Seeds the knowledge_embeddings table with high-quality HVAC Q&A pairs
 * generated by Gemini Flash (cheapest model, max quality per dollar).
 *
 * Cost guardrail: stops if estimated daily spend reaches $10.
 * Approximate cost: ~$0.0001 per Q&A pair for generation + negligible for embedding.
 * At that rate, $10 = ~100,000 pairs — we'll generate ~600 quality pairs for HVAC.
 *
 * Usage:
 *   node scripts/seed-knowledge-hvac.js
 *   node scripts/seed-knowledge-hvac.js --dry-run   (estimate only, no writes)
 */

require('dotenv').config({ path: require('path').join(__dirname, '../.env') });

const { GoogleGenerativeAI } = require('@google/generative-ai');
const supabase = require('../lib/supabase');
const { embedText } = require('../lib/embeddings');

// ── Config ─────────────────────────────────────────────────────────────────────
const GENERATION_MODEL  = process.env.GEMINI_MODEL_FLASH || 'gemini-2.5-flash';
const DAILY_COST_LIMIT  = 10.00;  // USD
const BATCH_DELAY_MS    = 500;    // ms between Gemini calls (rate limit safety)
const PAIRS_PER_TOPIC   = 6;      // Q&A pairs per request (keeps JSON well within token limits)

// Gemini Flash pricing (per 1M tokens) — for cost estimation
const COST_INPUT_PER_M  = 0.075;
const COST_OUTPUT_PER_M = 0.30;
const COST_EMBED_PER_M  = 0.00002; // text-embedding-001 per 1K chars ≈ negligible

const DRY_RUN = process.argv.includes('--dry-run');

// ── HVAC Topic Tree ────────────────────────────────────────────────────────────
const HVAC_TOPICS = [
  {
    category: 'Air Filters',
    subtopics: [
      'filter types (fiberglass, pleated, HEPA, electrostatic) and when to use each',
      'MERV ratings explained — what does MERV 8, 11, 13 mean for homeowners',
      'how often to change filters based on home type, pets, allergies',
      'signs a filter is clogged and what happens if you ignore it',
      'how to measure and select the right filter size',
    ],
  },
  {
    category: 'Air Conditioning',
    subtopics: [
      'annual AC tune-up checklist — what a homeowner can do vs what needs a tech',
      'refrigerant — signs of low refrigerant, when to recharge, R-22 vs R-410A',
      'AC not cooling — systematic troubleshooting from thermostat to condenser',
      'AC frozen evaporator coil — causes, how to thaw it, prevention',
      'condenser unit maintenance — cleaning coils, clearing debris, fan blade inspection',
      'AC capacitor failure — symptoms, safety warnings, when to DIY vs call pro',
      'AC contactor failure — what it does, symptoms, replacement guidance',
      'short cycling — why the AC keeps turning on and off',
    ],
  },
  {
    category: 'Furnaces',
    subtopics: [
      'gas furnace annual maintenance checklist',
      'furnace not igniting — pilot light vs electronic ignition troubleshooting',
      'furnace blower motor issues — symptoms and maintenance',
      'heat exchanger cracks — how to detect, why it is dangerous, next steps',
      'furnace error codes — how to read and interpret common codes',
      'furnace filter vs air handler filter — differences and locations',
    ],
  },
  {
    category: 'Heat Pumps',
    subtopics: [
      'how a heat pump works — heating and cooling explained simply',
      'heat pump vs furnace — when each makes sense, efficiency comparison',
      'heat pump defrost cycle — normal vs problem, what homeowners should know',
      'heat pump not heating in cold weather — balance point, aux heat, troubleshooting',
      'mini-split heat pump maintenance — cleaning filters, coils, drain lines',
    ],
  },
  {
    category: 'Ductwork & Airflow',
    subtopics: [
      'duct leakage — how to detect it, DIY sealing with mastic, when to call a pro',
      'uneven cooling and heating room-to-room — causes and fixes',
      'supply vs return vents — how to identify, balance, and never block them',
      'duct cleaning — when it is worth it and when it is not',
    ],
  },
  {
    category: 'Thermostats',
    subtopics: [
      'thermostat troubleshooting — blank screen, wrong temperature, not responding',
      'smart thermostat installation — wiring basics, C-wire requirement, compatibility',
      'thermostat calibration and placement best practices',
    ],
  },
  {
    category: 'Indoor Air Quality',
    subtopics: [
      'humidity levels — ideal range, dehumidifier vs humidifier, health effects',
      'UV light air purifiers — do they work, where to install, maintenance',
      'carbon monoxide from HVAC — sources, detector placement, what to do if alarm trips',
    ],
  },
  {
    category: 'Seasonal & Preventive Maintenance',
    subtopics: [
      'spring AC startup checklist before first use of the season',
      'fall furnace startup checklist — safety checks, test run, filter replacement',
      'winterizing window AC units and through-wall units',
      'HVAC maintenance schedule — monthly, quarterly, annual tasks',
      'HVAC system lifespan — when to repair vs replace decision framework',
    ],
  },
];

// ── Prompt Template ────────────────────────────────────────────────────────────
function buildPrompt(category, subtopic, count) {
  return `You are a master HVAC technician with 30+ years of field experience training residential maintenance workers. 

Generate exactly ${count} realistic question-and-answer pairs about: "${subtopic}" (category: ${category}).

Requirements:
- Questions must sound like real homeowners or maintenance techs would ask them
- Answers must be accurate, practical, and actionable (not vague)
- Include specific numbers where relevant (temperatures, pressures, MERV ratings, costs, intervals)
- Flag safety hazards clearly (e.g., "call a licensed tech", "turn off power first")
- Mix question difficulty: some basic, some intermediate, some advanced
- Do NOT use markdown — plain text only
- Keep each answer under 200 words

Return ONLY a JSON array in this exact format (no other text):
[
  { "question": "...", "answer": "..." },
  { "question": "...", "answer": "..." }
]`;
}

// ── Cost Tracker ───────────────────────────────────────────────────────────────
let totalInputTokens  = 0;
let totalOutputTokens = 0;
let totalPairsStored  = 0;
let totalErrors       = 0;

function estimatedCost() {
  return (
    (totalInputTokens  / 1_000_000) * COST_INPUT_PER_M  +
    (totalOutputTokens / 1_000_000) * COST_OUTPUT_PER_M
  );
}

function sleep(ms) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

// ── Generate Q&A for one subtopic ─────────────────────────────────────────────
async function generatePairs(genModel, category, subtopic, attempt = 1) {
  const prompt = buildPrompt(category, subtopic, PAIRS_PER_TOPIC);

  const result = await genModel.generateContent({
    contents: [{ role: 'user', parts: [{ text: prompt }] }],
    generationConfig: {
      maxOutputTokens: 8192,
      temperature: attempt === 1 ? 0.7 : 0.4, // lower temp on retry
      responseMimeType: 'application/json',
    },
  });

  const usage = result.response?.usageMetadata;
  totalInputTokens  += usage?.promptTokenCount     || 0;
  totalOutputTokens += usage?.candidatesTokenCount || 0;

  let raw = result.response.text().trim();

  // Strip markdown code fences if present
  raw = raw.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/i, '').trim();

  let pairs;
  try {
    pairs = JSON.parse(raw);
  } catch (parseErr) {
    // Attempt to salvage: find the last complete object and close the array
    const lastGood = raw.lastIndexOf('},');
    if (lastGood > 10) {
      try {
        pairs = JSON.parse(raw.substring(0, lastGood + 1) + ']');
      } catch (_) {
        // If retry available, try again
        if (attempt < 3) {
          await sleep(1000);
          return generatePairs(genModel, category, subtopic, attempt + 1);
        }
        throw new Error(`JSON parse failed after ${attempt} attempts: ${parseErr.message}`);
      }
    } else if (attempt < 3) {
      await sleep(1000);
      return generatePairs(genModel, category, subtopic, attempt + 1);
    } else {
      throw parseErr;
    }
  }

  if (!Array.isArray(pairs)) throw new Error('Response was not a JSON array');
  return pairs;
}

// ── Store one Q&A pair ────────────────────────────────────────────────────────
async function storePair(question, answer, category, subtopic) {
  if (DRY_RUN) { totalPairsStored++; return; }

  // Embed the combined Q+A
  const content = `Q: ${question}\nA: ${answer}`;
  const embedding = await embedText(content);

  if (!embedding || embedding.length === 0) {
    throw new Error('Empty embedding returned');
  }

  const { error } = await supabase
    .from('knowledge_embeddings')
    .insert({
      content,
      embedding,
      metadata: {
        source:     'seed_hvac',
        category:   category.toLowerCase().replace(/\s+/g, '_'),
        subtopic,
        confidence: 0.95, // seeded by expert model — high confidence
        seeded:     true,
      },
    });

  if (error) throw new Error(`DB insert failed: ${error.message}`);
  totalPairsStored++;
}

// ── Main ──────────────────────────────────────────────────────────────────────
async function main() {
  console.log('\n🔧 MaintMentor HVAC Knowledge Seeder');
  console.log(`   Model  : ${GENERATION_MODEL}`);
  console.log(`   Topics : ${HVAC_TOPICS.length} categories`);
  console.log(`   Limit  : $${DAILY_COST_LIMIT}/day`);
  if (DRY_RUN) console.log('   MODE   : DRY RUN (no writes)\n');
  else         console.log('   MODE   : LIVE\n');

  // Count total subtopics
  const totalSubtopics = HVAC_TOPICS.reduce((s, t) => s + t.subtopics.length, 0);
  const estimatedPairs = totalSubtopics * PAIRS_PER_TOPIC;
  console.log(`   Subtopics : ${totalSubtopics}`);
  console.log(`   Est. pairs: ~${estimatedPairs}`);
  console.log('');

  const genAI    = new GoogleGenerativeAI(process.env.GEMINI_API_KEY);
  const genModel = genAI.getGenerativeModel({ model: GENERATION_MODEL });

  for (const topic of HVAC_TOPICS) {
    console.log(`\n📂 ${topic.category}`);

    for (const subtopic of topic.subtopics) {
      // Cost guardrail
      if (estimatedCost() >= DAILY_COST_LIMIT) {
        console.log(`\n⛔ Daily cost limit reached ($${DAILY_COST_LIMIT}). Stopping.`);
        break;
      }

      process.stdout.write(`   ⚙️  ${subtopic.substring(0, 60)}...`);

      try {
        // Run 2 batches per subtopic (2 × 6 = 12 pairs, reliable JSON each time)
        let subtopicPairs = 0;
        for (let batch = 0; batch < 2; batch++) {
          const pairs = await generatePairs(genModel, topic.category, subtopic);
          for (const pair of pairs) {
            if (!pair.question || !pair.answer) continue;
            try {
              await storePair(pair.question, pair.answer, topic.category, subtopic);
              subtopicPairs++;
            } catch (storeErr) {
              totalErrors++;
            }
          }
          await sleep(BATCH_DELAY_MS);
        }

        const cost = estimatedCost();
        process.stdout.write(` ✅ ${subtopicPairs} pairs (est. $${cost.toFixed(4)} total)\n`);
      } catch (err) {
        process.stdout.write(` ❌ ${err.message}\n`);
        totalErrors++;
      }

      await sleep(BATCH_DELAY_MS);
    }
  }

  // ── Summary ──
  const finalCost = estimatedCost();
  console.log('\n' + '─'.repeat(55));
  console.log('✅ HVAC Seeding Complete');
  console.log(`   Pairs stored   : ${totalPairsStored}`);
  console.log(`   Errors         : ${totalErrors}`);
  console.log(`   Tokens in/out  : ${totalInputTokens.toLocaleString()} / ${totalOutputTokens.toLocaleString()}`);
  console.log(`   Estimated cost : $${finalCost.toFixed(4)}`);
  console.log('─'.repeat(55) + '\n');
}

main().catch(err => {
  console.error('\nFatal:', err.message);
  process.exit(1);
});
